"use client";
import Link from "next/link";
import { usePathname } from "next/navigation";

const navLinks = [
  { href: "/",        label: "Home"         },
  { href: "/channel", label: "Book Doctor"  },
  { href: "/about",   label: "About"        },
  { href: "/contact", label: "Contact"      },
];

export default function Navbar() {
  const pathname = usePathname();

  return (
    <nav style={{
      position: "sticky", top: 0, zIndex: 50,
      backdropFilter: "blur(20px)", WebkitBackdropFilter: "blur(20px)",
      background: "rgba(2,8,24,0.75)",
      borderBottom: "1px solid rgba(56,189,248,0.09)",
    }}>
      <div style={{
        maxWidth: 1000, margin: "0 auto",
        padding: "0 24px", height: 64,
        display: "flex", alignItems: "center", justifyContent: "space-between",
      }}>
        {/* Logo */}
        <Link href="/" style={{ textDecoration: "none", display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{
            width: 36, height: 36, borderRadius: 10,
            background: "linear-gradient(135deg, #0ea5e9, #6366f1)",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 17, boxShadow: "0 0 14px rgba(14,165,233,0.35)",
            flexShrink: 0,
          }}>💊</div>
          <div>
            <div style={{
              fontFamily: "Syne, sans-serif", fontWeight: 800, fontSize: 17,
              background: "linear-gradient(135deg, #38bdf8, #818cf8)",
              WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
              backgroundClip: "text", lineHeight: 1,
            }}>Healix</div>
            <div style={{ color: "#334155", fontSize: 10, fontWeight: 500, letterSpacing: 1 }}>
              eCHANNELLING
            </div>
          </div>
        </Link>

        {/* Nav links */}
        <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
          {navLinks.map(link => {
            const active = pathname === link.href;
            return (
              <Link key={link.href} href={link.href} style={{
                textDecoration: "none",
                padding: "6px 14px",
                borderRadius: 8,
                fontSize: 13,
                fontWeight: active ? 600 : 500,
                color: active ? "#38bdf8" : "#64748b",
                background: active ? "rgba(14,165,233,0.1)" : "transparent",
                border: active ? "1px solid rgba(56,189,248,0.18)" : "1px solid transparent",
                transition: "all 0.2s",
              }}
              onMouseEnter={e => { if (!active) { e.currentTarget.style.color = "#94a3b8"; e.currentTarget.style.background = "rgba(255,255,255,0.03)"; } }}
              onMouseLeave={e => { if (!active) { e.currentTarget.style.color = "#64748b"; e.currentTarget.style.background = "transparent"; } }}
              >
                {link.label}
              </Link>
            );
          })}
        </div>

        {/* Right — live indicator + CTA */}
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <div style={{
              width: 7, height: 7, borderRadius: "50%",
              background: "#22c55e",
              boxShadow: "0 0 0 0 rgba(34,197,94,0.4)",
              animation: "pulse-ring 2s infinite",
            }} />
            <span style={{ color: "#475569", fontSize: 12 }}>Live</span>
          </div>
          <Link href="/channel" style={{
            textDecoration: "none", padding: "7px 16px",
            background: "linear-gradient(135deg, #0ea5e9, #38bdf8)",
            color: "#fff", borderRadius: 9, fontSize: 13, fontWeight: 600,
            boxShadow: "0 0 14px rgba(14,165,233,0.3)",
            transition: "box-shadow 0.2s, transform 0.2s",
          }}
          onMouseEnter={e => { e.currentTarget.style.boxShadow = "0 0 22px rgba(14,165,233,0.5)"; e.currentTarget.style.transform = "translateY(-1px)"; }}
          onMouseLeave={e => { e.currentTarget.style.boxShadow = "0 0 14px rgba(14,165,233,0.3)"; e.currentTarget.style.transform = "none"; }}
          >
            Book Now
          </Link>
        </div>
      </div>
    </nav>
  );
}